def env_list(name: str, default: str = "") -> List[str]:
    value = os.getenv(name, default)
    return [item.strip() for item in value.split(",") if item.strip()]


def build_config_from_env() -> ConsumerConfig:
    return ConsumerConfig(
        bootstrap_servers=env_list("KAFKA_BOOTSTRAP_SERVERS", "localhost:9092"),
        topics=env_list("KAFKA_TOPICS", "transactions"),
        group_id=os.getenv("KAFKA_GROUP_ID", "transaction-processing-group"),
        auto_offset_reset=os.getenv("KAFKA_AUTO_OFFSET_RESET", "earliest"),
        enable_auto_commit=os.getenv("KAFKA_ENABLE_AUTO_COMMIT", "false").lower() == "true",
        max_poll_records=int(os.getenv("KAFKA_MAX_POLL_RECORDS", "100")),
        poll_timeout_ms=int(os.getenv("KAFKA_POLL_TIMEOUT_MS", "1000")),
        trusted_handler_modules=env_list("TRUSTED_HANDLER_MODULES"),
        trusted_message_types=env_list("TRUSTED_MESSAGE_TYPES"),
        allow_pickle=os.getenv("ALLOW_PICKLE", "false").lower() == "true",
        client_id=os.getenv("KAFKA_CLIENT_ID", "transaction-consumer"),
    )


